frq_section.reference_solution:
public class NameProcessor {
    private String fullName;

    public NameProcessor(String name) {
        fullName = name;
    }

    public String firstLetter(String word) {
        return word.substring(0, 1).toUpperCase();
    }

    public String getInitials() {
        String result = "";
        String remaining = fullName;
        while (remaining.indexOf(" ") != -1) {
            int spaceIdx = remaining.indexOf(" ");
            String word = remaining.substring(0, spaceIdx);
            result += firstLetter(word);
            remaining = remaining.substring(spaceIdx + 1);
        }
        result += firstLetter(remaining);
        return result;
    }
}

